using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, new OpenAIClient(apiKey))
    .AsIChatClient();

// --- Tools ---
var notebook = new ResearchNotebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
var webSearch = new WebSearchTool(httpClient);

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. Follow this workflow:
        1. Search the web for the requested topic using different queries.
        2. Fetch promising pages to get detailed content.
        3. Save key findings as notes with descriptive titles.
        4. After gathering enough information (at least 2-3 notes), retrieve
           all your notes and write a comprehensive summary with references.
        Be factual and cite your sources.
        """,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking",
    tools: tools);

// --- Run ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

// Display collected notes
var notes = notebook.GetAllNotes();
if (notes.Count > 0)
{
    Console.WriteLine("\n📝 Research Notes Collected:");
    Console.WriteLine(new string('─', 50));
    foreach (var note in notes)
    {
        Console.WriteLine($"\n## {note.Title}");
        Console.WriteLine(note.Content);
    }
}

// --- Tool implementations ---

/// <summary>Web search tool using DuckDuckGo and page fetching.</summary>
sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for a query. Returns a list of result titles, URLs, and snippets.")]
    public async Task<IReadOnlyList<SearchResult>> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: {query}");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await httpClient.GetStringAsync(url);

            var results = new List<SearchResult>();
            // Parse DuckDuckGo HTML results
            var snippetMarker = "class=\"result__snippet\"";
            var titleMarker = "class=\"result__a\"";
            var hrefMarker = "href=\"";

            var pos = 0;
            while (results.Count < 5 && pos < html.Length)
            {
                var titleIdx = html.IndexOf(titleMarker, pos, StringComparison.Ordinal);
                if (titleIdx < 0) break;

                // Extract href
                var hrefIdx = html.LastIndexOf(hrefMarker, titleIdx, Math.Min(titleIdx, 200), StringComparison.Ordinal);
                var resultUrl = "";
                if (hrefIdx >= 0)
                {
                    hrefIdx += hrefMarker.Length;
                    var hrefEnd = html.IndexOf('"', hrefIdx);
                    if (hrefEnd > hrefIdx)
                        resultUrl = html[hrefIdx..hrefEnd];
                }

                // Extract title text
                var titleStart = html.IndexOf('>', titleIdx) + 1;
                var titleEnd = html.IndexOf('<', titleStart);
                var title = titleEnd > titleStart
                    ? StripHtml(html[titleStart..titleEnd])
                    : "Untitled";

                // Extract snippet
                var snippet = "";
                var snippetIdx = html.IndexOf(snippetMarker, titleIdx, StringComparison.Ordinal);
                if (snippetIdx >= 0 && snippetIdx - titleIdx < 2000)
                {
                    var snipStart = html.IndexOf('>', snippetIdx) + 1;
                    var snipEnd = html.IndexOf("</", snipStart, StringComparison.Ordinal);
                    if (snipEnd > snipStart)
                        snippet = StripHtml(html[snipStart..Math.Min(snipEnd, snipStart + 300)]);
                }

                if (!string.IsNullOrWhiteSpace(title))
                    results.Add(new SearchResult(title.Trim(), resultUrl.Trim(), snippet.Trim()));

                pos = titleIdx + 1;
            }

            Console.WriteLine($"  ✅ Found {results.Count} results");
            return results;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ⚠️  Search failed: {ex.Message}");
            return [new SearchResult("Error", "", $"Search failed: {ex.Message}")];
        }
    }

    [Description("Fetch and extract text content from a web page URL.")]
    public async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            if (url.StartsWith("//"))
                url = "https:" + url;

            var html = await httpClient.GetStringAsync(url);
            var text = StripHtml(html);

            // Collapse whitespace and truncate
            var sb = new StringBuilder();
            var prevSpace = false;
            foreach (var ch in text)
            {
                if (char.IsWhiteSpace(ch))
                {
                    if (!prevSpace) sb.Append(' ');
                    prevSpace = true;
                }
                else
                {
                    sb.Append(ch);
                    prevSpace = false;
                }
            }

            var cleaned = sb.ToString().Trim();
            const int maxLen = 3000;
            if (cleaned.Length > maxLen)
                cleaned = cleaned[..maxLen] + "... [truncated]";

            Console.WriteLine($"  ✅ Fetched {cleaned.Length} chars");
            return cleaned;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ⚠️  Fetch failed: {ex.Message}");
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, then decode entities
        var text = System.Text.RegularExpressions.Regex.Replace(
            html, @"<(script|style)[^>]*>.*?</\1>", "", System.Text.RegularExpressions.RegexOptions.Singleline);
        text = System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        return text;
    }
}

record SearchResult(string Title, string Url, string Snippet);

/// <summary>In-memory note-taking tool for organizing research findings.</summary>
sealed class ResearchNotebook
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and content. Use this to record key findings.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The content/findings to save")] string content)
    {
        _notes.Add(new Note(title, content));
        Console.WriteLine($"  📝 Note saved: {title}");
        return $"Note '{title}' saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public IReadOnlyList<Note> GetAllNotes()
    {
        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        return _notes.AsReadOnly();
    }
}

record Note(string Title, string Content);

