using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, new OpenAIClient(apiKey))
    .AsIChatClient();

// --- Tools ---
var notebook = new ResearchNotebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
var webSearch = new WebSearchTool(httpClient);

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a thorough research agent. Follow this workflow:
        1. Search the web for the requested topic using different queries.
        2. Fetch promising pages to get detailed content.
        3. Save key findings as notes with descriptive titles.
        4. After gathering enough information (at least 2-3 notes), retrieve
           all your notes and write a comprehensive summary with references.
        Be factual and cite your sources.
        """,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking",
    tools: tools);

// --- Run ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

// Display collected notes
var notes = notebook.GetAllNotes();
if (notes.Count > 0)
{
    Console.WriteLine("\n📝 Research Notes Collected:");
    Console.WriteLine(new string('─', 50));
    foreach (var note in notes)
    {
        Console.WriteLine($"\n## {note.Title}");
        Console.WriteLine(note.Content);
    }
}

// --- Tool implementations ---

